    89	        cols: u32,
    90	        left: []const u8,
    91	        center: []const u8,
    92	        right: []const u8,
    93	    ) ![]u8 {
    94	        if (!self.enabled or cols == 0) {
    95	            return try alloc.alloc(u8, 0);
    96	        }
    97	
    98	        var line: std.ArrayListAligned(u8, null) = .empty;
    99	        errdefer line.deinit(alloc);
   100	
   101	        var current_style = self.style;
   102	        try appendStyleSequence(&line, alloc, current_style);
   103	
   104	        const right_visible_len = @min(visibleLen(right), cols);
   105	        const leading_budget = cols - right_visible_len;
   106	        var leading_len: usize = 0;
   107	
   108	        leading_len += try appendStyledText(&line, alloc, left, self.style, &current_style, leading_budget - leading_len);
   109	
   110	        if (center.len > 0 and leading_len < leading_budget) {
   111	            if (left.len > 0) {
   112	                try line.append(alloc, ' ');
   113	                leading_len += 1;
   114	            }
   115	            leading_len += try appendStyledText(&line, alloc, center, self.style, &current_style, leading_budget - leading_len);
   116	        }
